#!/usr/bin/env node
// Extract memory values from an ELF binary.
// Loads PT_LOAD segments into a virtual-memory image and emits every
// 4-byte little-endian word (4-aligned) at its virtual address.
const fs = require('fs');

const path = process.argv[2];
if (!path) { console.error('usage: node extract.js <binary>'); process.exit(1); }
const buf = fs.readFileSync(path);

// --- ELF header ---
if (buf.length < 64 || buf[0] !== 0x7f || buf[1] !== 0x45 || buf[2] !== 0x4c || buf[3] !== 0x46) {
  console.error('not an ELF file');
  process.exit(1);
}
const is64 = buf[4] === 2;            // EI_CLASS
const le = buf[5] === 1;              // EI_DATA (little endian)
const rd16 = (o) => le ? buf.readUInt16LE(o) : buf.readUInt16BE(o);
const rd32 = (o) => le ? buf.readUInt32LE(o) : buf.readUInt32BE(o);
const rd64 = (o) => le ? Number(buf.readBigUInt64LE(o)) : Number(buf.readBigUInt64BE(o));

const eType = rd16(16);               // ET_EXEC=2, ET_DYN=3
// Non-PIE executables already carry absolute vaddrs; PIE binaries start at 0,
// so give them the canonical 0x400000 load base.
const base = (eType === 3) ? 0x400000 : 0;

let phoff, phentsize, phnum;
if (is64) {
  phoff = rd64(32); phentsize = rd16(54); phnum = rd16(56);
} else {
  phoff = rd32(28); phentsize = rd16(42); phnum = rd16(44);
}

const PT_LOAD = 1;
const out = {};

for (let i = 0; i < phnum; i++) {
  const ph = phoff + i * phentsize;
  const pType = rd32(ph);
  if (pType !== PT_LOAD) continue;

  let pOffset, pVaddr, pFilesz;
  if (is64) {
    pOffset = rd64(ph + 8);
    pVaddr  = rd64(ph + 16);
    pFilesz = rd64(ph + 32);
  } else {
    pOffset = rd32(ph + 4);
    pVaddr  = rd32(ph + 8);
    pFilesz = rd32(ph + 16);
  }

  const vaddr = base + pVaddr;
  // Emit 4-byte aligned words over the file-backed portion of the segment.
  for (let off = 0; off + 4 <= pFilesz; off += 4) {
    const faddr = pOffset + off;
    if (faddr + 4 > buf.length) break;
    const addr = vaddr + off;
    if (addr % 4 !== 0) continue;
    out[addr] = le ? buf.readUInt32LE(faddr) : buf.readUInt32BE(faddr);
  }
}

process.stdout.write(JSON.stringify(out) + '\n');

